import clsx from 'clsx';
import { type PropsWithChildren } from 'react';

import type { StylingProps } from '../../../../../core/types/styling-props.js';
import { useBodyHeightStyle } from '../ChartTooltip/hooks/useBodyHeightStyle.js';
import { container } from '../shared/styles/TooltipBody.sty.js';

export const NonVirtualizedTooltipBody = (
  props: PropsWithChildren<StylingProps>,
) => {
  const {
    children,
    style: consumerStyle,
    className: consumerClassname,
  } = props;

  const bodyHeightStyle = useBodyHeightStyle();

  return (
    <div
      className={clsx(container, consumerClassname)}
      style={{ ...bodyHeightStyle, ...consumerStyle }}
    >
      {children}
    </div>
  );
};

NonVirtualizedTooltipBody['displayName'] = 'NonVirtualizedTooltipBody';
